css:
@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&family=DM+Sans:ital,wght@0,400;0,500;0,600;0,700;1,400&family=Playfair+Display:wght@700;800;900&display=swap');

.cover{min-height:100vh;display:flex;flex-direction:column;justify-content:center;align-items:center;text-align:center;position:relative;overflow:hidden;padding:60px 40px;background:radial-gradient(ellipse 80% 60% at 50% 0%, rgba(232,112,64,0.12) 0%, transparent 60%), var(--bg0);}
.cover-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(232,112,64,0.1);border:1px solid rgba(232,112,64,0.25);border-radius:100px;padding:8px 20px;font-family:'JetBrains Mono',monospace;font-size:13px;color:var(--co);letter-spacing:0.5px;margin-bottom:40px;}
.cover h1{font-family:'Playfair Display',serif;font-size:clamp(44px,7vw,80px);font-weight:900;line-height:1.05;margin-bottom:8px;}
.hl{background:linear-gradient(135deg,var(--co),var(--co-l));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.cover h2{font-family:'Playfair Display',serif;font-size:clamp(24px,4vw,40px);font-weight:700;color:var(--tx2);margin-bottom:28px;}
.cover p{font-size:17px;color:var(--tx2);max-width:520px;margin-bottom:48px;}
.cover-meta{display:flex;gap:28px;flex-wrap:wrap;justify-content:center;font-family:'JetBrains Mono',monospace;font-size:12px;color:var(--tx3);}
.cover-meta span::before{content:'\25C6 ';color:var(--co);font-size:6px;vertical-align:middle;}
.toc{max-width:760px;margin:0 auto;padding:80px 40px;}
.section-label{font-family:'JetBrains Mono',monospace;font-size:12px;text-transform:uppercase;letter-spacing:3px;color:var(--co);margin-bottom:40px;display:block;}
.toc-item{display:flex;align-items:baseline;gap:16px;padding:14px 0;border-bottom:1px solid var(--brd);}
.toc-n{font-family:'JetBrains Mono',monospace;font-size:13px;color:var(--co);min-width:28px;}
.toc-t{font-size:17px;font-weight:600;flex:1;}
.toc-s{font-size:13px;color:var(--tx3);font-family:'JetBrains Mono',monospace;}
.ch{max-width:760px;margin:0 auto;padding:72px 40px;}
.ch-head{margin-bottom:40px;padding-bottom:28px;border-bottom:2px solid var(--brd);position:relative;}
.ch-head::after{content:'';position:absolute;bottom:-2px;left:0;width:100px;height:2px;background:var(--co);}
.ch-num{font-family:'JetBrains Mono',monospace;font-size:12px;text-transform:uppercase;letter-spacing:3px;color:var(--co);margin-bottom:10px;display:block;}
.ch-title{font-family:'Playfair Display',serif;font-size:32px;font-weight:800;line-height:1.15;margin-bottom:10px;}
.ch-obj{font-size:16px;color:var(--tx2);font-style:italic;}
.chapter-inner h1,.chapter-inner h2,.chapter-inner h3{font-family:'Playfair Display',serif;margin:28px 0 12px;}
.chapter-inner h1{font-size:30px;}
.chapter-inner h2{font-size:22px;color:var(--co);}
.chapter-inner h3{font-size:18px;}
.chapter-inner p{margin-bottom:14px;color:var(--tx2);}
.chapter-inner ul,.chapter-inner ol{margin:12px 0 18px 24px;color:var(--tx2);}
.chapter-inner code{font-family:'JetBrains Mono',monospace;font-size:0.88em;background:rgba(232,112,64,0.08);color:var(--co-l);padding:2px 7px;border-radius:4px;}
.chapter-inner pre{background:var(--bgt);border:1px solid var(--brd);border-radius:8px;padding:16px 20px;overflow-x:auto;font-family:'JetBrains Mono',monospace;font-size:13px;margin:14px 0;}
.chapter-inner blockquote{border-left:3px solid var(--co);padding:6px 16px;color:var(--tx2);font-style:italic;margin:14px 0;background:rgba(232,112,64,0.04);}
